CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE tenants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE brands (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE memberships (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), user_id text NOT NULL, role text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,user_id));
CREATE TABLE sources (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, connector_type text NOT NULL, config jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE signals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), source_id uuid NOT NULL REFERENCES sources(id), fingerprint text NOT NULL, payload jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,fingerprint));
CREATE TABLE opportunities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, description text NOT NULL DEFAULT '', status text NOT NULL, score integer NOT NULL DEFAULT 0 CHECK(score BETWEEN 0 AND 100), version integer NOT NULL DEFAULT 1, created_by text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,id));
CREATE TABLE opportunity_evidence (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), opportunity_id uuid NOT NULL REFERENCES opportunities(id), kind text NOT NULL, summary text NOT NULL, confidence integer NOT NULL CHECK(confidence BETWEEN 0 AND 100), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE incubation_projects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), opportunity_id uuid NOT NULL REFERENCES opportunities(id), name text NOT NULL, status text NOT NULL, version integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE business_blueprints (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), source_opportunity_id uuid NOT NULL REFERENCES opportunities(id), name text NOT NULL, description text NOT NULL DEFAULT '', version integer NOT NULL, status text NOT NULL, definition jsonb NOT NULL, created_by text NOT NULL, approved_by text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,id,version));
CREATE TABLE capabilities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, definition jsonb NOT NULL DEFAULT '{}', UNIQUE(tenant_id,name));
CREATE TABLE providers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, status text NOT NULL, UNIQUE(tenant_id,name));
CREATE TABLE provider_endpoints (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), provider_id uuid NOT NULL REFERENCES providers(id), capability_id uuid NOT NULL REFERENCES capabilities(id), adapter_type text NOT NULL, adapter_version text NOT NULL, config_secret_ref text, status text NOT NULL);
CREATE TABLE products (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), blueprint_id uuid NOT NULL REFERENCES business_blueprints(id), name text NOT NULL, status text NOT NULL, version integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE product_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), product_id uuid NOT NULL REFERENCES products(id), version integer NOT NULL, definition jsonb NOT NULL, input_schema jsonb NOT NULL, output_schema jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,product_id,version));
CREATE TABLE skus (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), product_id uuid NOT NULL REFERENCES products(id), code text NOT NULL, UNIQUE(tenant_id,code));
CREATE TABLE sku_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), sku_id uuid NOT NULL REFERENCES skus(id), product_version_id uuid NOT NULL REFERENCES product_versions(id), version integer NOT NULL, bindings jsonb NOT NULL, UNIQUE(tenant_id,sku_id,version));
CREATE TABLE workflow_definitions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, version integer NOT NULL, definition jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,id,version));
CREATE TABLE workflow_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), definition_id uuid NOT NULL REFERENCES workflow_definitions(id), idempotency_key text NOT NULL, status text NOT NULL, variables jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,definition_id,idempotency_key));
CREATE TABLE workflow_step_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), run_id uuid NOT NULL REFERENCES workflow_runs(id), node_id text NOT NULL, status text NOT NULL, attempt integer NOT NULL, output jsonb, error jsonb, started_at timestamptz, completed_at timestamptz, UNIQUE(tenant_id,run_id,node_id,attempt));
CREATE TABLE metering_definitions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, version integer NOT NULL, definition jsonb NOT NULL, UNIQUE(tenant_id,id,version));
CREATE TABLE price_books (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), currency char(3) NOT NULL, version integer NOT NULL, status text NOT NULL, UNIQUE(tenant_id,id,version));
CREATE TABLE price_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), price_book_id uuid NOT NULL REFERENCES price_books(id), priority integer NOT NULL, definition jsonb NOT NULL);
CREATE TABLE route_policies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), name text NOT NULL, version integer NOT NULL, definition jsonb NOT NULL, UNIQUE(tenant_id,id,version));
CREATE TABLE orders (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), customer_id text NOT NULL, status text NOT NULL, currency char(3) NOT NULL, amount_minor bigint NOT NULL CHECK(amount_minor>=0), idempotency_key text NOT NULL, version_bindings jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,idempotency_key));
CREATE TABLE usage_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), order_id uuid NOT NULL REFERENCES orders(id), meter_id uuid NOT NULL REFERENCES metering_definitions(id), quantity bigint NOT NULL CHECK(quantity>=0), occurred_at timestamptz NOT NULL);
CREATE TABLE provider_costs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), order_id uuid NOT NULL REFERENCES orders(id), provider_endpoint_id uuid NOT NULL REFERENCES provider_endpoints(id), currency char(3) NOT NULL, amount_minor bigint NOT NULL CHECK(amount_minor>=0));
CREATE TABLE customer_charges (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), order_id uuid NOT NULL REFERENCES orders(id), price_book_id uuid NOT NULL REFERENCES price_books(id), currency char(3) NOT NULL, amount_minor bigint NOT NULL CHECK(amount_minor>=0));
CREATE TABLE ledger_accounts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), code text NOT NULL, name text NOT NULL, account_type text NOT NULL, currency char(3) NOT NULL, UNIQUE(tenant_id,code));
CREATE TABLE ledger_transactions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), idempotency_key text NOT NULL, reference_type text NOT NULL, reference_id text NOT NULL, description text NOT NULL, reverses_transaction_id uuid REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,idempotency_key));
CREATE TABLE ledger_entries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), transaction_id uuid NOT NULL REFERENCES ledger_transactions(id), account_id uuid NOT NULL REFERENCES ledger_accounts(id), direction text NOT NULL CHECK(direction IN ('debit','credit')), currency char(3) NOT NULL, amount_minor bigint NOT NULL CHECK(amount_minor>0), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE outcome_feedback (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), opportunity_id uuid NOT NULL REFERENCES opportunities(id), order_id uuid REFERENCES orders(id), metrics jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE feature_definitions (key text PRIMARY KEY, description text NOT NULL, default_enabled boolean NOT NULL DEFAULT false);
CREATE TABLE tenant_features (tenant_id uuid NOT NULL REFERENCES tenants(id), feature_key text NOT NULL REFERENCES feature_definitions(key), enabled boolean NOT NULL, release_channel text NOT NULL DEFAULT 'stable', PRIMARY KEY(tenant_id,feature_key));
CREATE TABLE audit_log (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), actor_id text NOT NULL, action text NOT NULL, object_type text NOT NULL, object_id text NOT NULL, request_id text NOT NULL, trace_id text NOT NULL, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE outbox_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), aggregate_type text NOT NULL, aggregate_id text NOT NULL, event_type text NOT NULL, aggregate_version integer NOT NULL, trace_id text NOT NULL, payload jsonb NOT NULL, occurred_at timestamptz NOT NULL DEFAULT now(), processed_at timestamptz, retry_count integer NOT NULL DEFAULT 0, next_retry_at timestamptz, dead_letter_reason text);
CREATE TABLE inbox_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), external_event_id text NOT NULL, idempotency_key text NOT NULL, payload jsonb NOT NULL, processed_at timestamptz, retry_count integer NOT NULL DEFAULT 0, next_retry_at timestamptz, dead_letter_reason text, UNIQUE(tenant_id,external_event_id), UNIQUE(tenant_id,idempotency_key));
CREATE INDEX idx_opportunities_tenant_status ON opportunities(tenant_id,status);
CREATE INDEX idx_outbox_pending ON outbox_events(processed_at,next_retry_at) WHERE processed_at IS NULL;
CREATE INDEX idx_audit_tenant_created ON audit_log(tenant_id,created_at DESC);

